import{_ as n,o as s,c as e,ag as l}from"./chunks/framework.D_Vktuop.js";const u=JSON.parse('{"title":"nanobot 架构设计","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md","lastUpdated":null}'),p={name:"guide/architecture.md"};function i(t,a,r,o,c,d){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="nanobot-架构设计" tabindex="-1">nanobot 架构设计 <a class="header-anchor" href="#nanobot-架构设计" aria-label="Permalink to &quot;nanobot 架构设计&quot;">​</a></h1><h2 id="核心设计理念" tabindex="-1">核心设计理念 <a class="header-anchor" href="#核心设计理念" aria-label="Permalink to &quot;核心设计理念&quot;">​</a></h2><p>nanobot 的设计遵循以下核心原则：</p><h3 id="_1-解耦" tabindex="-1">1. 解耦 <a class="header-anchor" href="#_1-解耦" aria-label="Permalink to &quot;1. 解耦&quot;">​</a></h3><p>通过消息总线（MessageBus）解耦聊天通道和代理核心，使得：</p><ul><li>新增聊天平台只需实现通道接口</li><li>代理核心不需要关心具体平台</li><li>各组件独立开发和测试</li></ul><h3 id="_2-异步" tabindex="-1">2. 异步 <a class="header-anchor" href="#_2-异步" aria-label="Permalink to &quot;2. 异步&quot;">​</a></h3><p>全面使用 asyncio 实现异步架构：</p><ul><li>高并发处理能力</li><li>非阻塞 I/O 操作</li><li>优秀的资源利用率</li></ul><h3 id="_3-插件化" tabindex="-1">3. 插件化 <a class="header-anchor" href="#_3-插件化" aria-label="Permalink to &quot;3. 插件化&quot;">​</a></h3><p>采用插件式架构：</p><ul><li>通道插件：轻松接入新的聊天平台</li><li>提供商插件：支持多种 LLM</li><li>工具插件：扩展 AI 能力</li></ul><h3 id="_4-轻量" tabindex="-1">4. 轻量 <a class="header-anchor" href="#_4-轻量" aria-label="Permalink to &quot;4. 轻量&quot;">​</a></h3><p>保持代码简洁和依赖最小化：</p><ul><li>核心代码约 4000 行</li><li>最小化外部依赖</li><li>清晰的代码结构</li></ul><h2 id="整体架构" tabindex="-1">整体架构 <a class="header-anchor" href="#整体架构" aria-label="Permalink to &quot;整体架构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        聊天平台                              │</span></span>
<span class="line"><span>│  (Telegram, Discord, WhatsApp, Feishu, QQ, ...)            │</span></span>
<span class="line"><span>└─────────────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>                              ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                   ChannelManager                           │</span></span>
<span class="line"><span>│              (通道管理器 - 管理所有通道)                      │</span></span>
<span class="line"><span>│                                                             │</span></span>
<span class="line"><span>│  Channels:                                                  │</span></span>
<span class="line"><span>│  - TelegramChannel                                          │</span></span>
<span class="line"><span>│  - DiscordChannel                                           │</span></span>
<span class="line"><span>│  - WhatsAppChannel                                          │</span></span>
<span class="line"><span>│  - FeishuChannel                                           │</span></span>
<span class="line"><span>│  - ...                                                      │</span></span>
<span class="line"><span>└─────────────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>                              ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      MessageBus                             │</span></span>
<span class="line"><span>│                   (消息总线 - 队列系统)                       │</span></span>
<span class="line"><span>│                                                             │</span></span>
<span class="line"><span>│  - inbound:  asyncio.Queue&lt;InboundMessage&gt;                │</span></span>
<span class="line"><span>│  - outbound: asyncio.Queue&lt;OutboundMessage&gt;                │</span></span>
<span class="line"><span>│  - 解耦通道和代理                                           │</span></span>
<span class="line"><span>└─────────────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>                              ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    AgentLoop (代理核心)                       │</span></span>
<span class="line"><span>│  - 消息分发                                                 │</span></span>
<span class="line"><span>│  - 会话管理                                                 │</span></span>
<span class="line"><span>│  - 上下文构建                                               │</span></span>
<span class="line"><span>│  - LLM 调用                                                │</span></span>
<span class="line"><span>│  - 工具执行                                                 │</span></span>
<span class="line"><span>└─────────────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>        ┌─────────────────────┴─────────────────────┐</span></span>
<span class="line"><span>        │                                           │</span></span>
<span class="line"><span>        ▼                                           ▼</span></span>
<span class="line"><span>┌──────────────────────┐              ┌──────────────────────────────┐</span></span>
<span class="line"><span>│   ToolRegistry      │              │      LLM Providers           │</span></span>
<span class="line"><span>│  (工具注册表)         │              │   (LLM 提供商)                │</span></span>
<span class="line"><span>│                     │              │                             │</span></span>
<span class="line"><span>│  - ReadFileTool     │              │  - LiteLLMProvider           │</span></span>
<span class="line"><span>│  - WriteFileTool    │              │  - CustomProvider            │</span></span>
<span class="line"><span>│  - EditFileTool     │              │  - OpenAICodexProvider       │</span></span>
<span class="line"><span>│  - ExecTool         │              │  - AzureOpenAIProvider       │</span></span>
<span class="line"><span>│  - WebSearchTool    │              │                             │</span></span>
<span class="line"><span>│  - WebFetchTool     │              │                             │</span></span>
<span class="line"><span>│  - MessageTool      │              │                             │</span></span>
<span class="line"><span>│  - SpawnTool        │              │                             │</span></span>
<span class="line"><span>│  - CronTool         │              │                             │</span></span>
<span class="line"><span>└──────────────────────┘              └──────────────────────────────┘</span></span>
<span class="line"><span>        │                                           │</span></span>
<span class="line"><span>        └─────────────────────┬─────────────────────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>                              ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  辅助服务                                     │</span></span>
<span class="line"><span>│  - SessionManager (会话管理)                                │</span></span>
<span class="line"><span>│  - CronService (定时任务)                                    │</span></span>
<span class="line"><span>│  - HeartbeatService (心跳服务)                               │</span></span>
<span class="line"><span>│  - SubagentManager (子代理管理)                              │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="分层架构" tabindex="-1">分层架构 <a class="header-anchor" href="#分层架构" aria-label="Permalink to &quot;分层架构&quot;">​</a></h2><h3 id="表现层-presentation-layer" tabindex="-1">表现层 (Presentation Layer) <a class="header-anchor" href="#表现层-presentation-layer" aria-label="Permalink to &quot;表现层 (Presentation Layer)&quot;">​</a></h3><ul><li><strong>通道系统</strong>: 处理不同聊天平台的消息收发</li><li><strong>CLI 界面</strong>: 命令行交互界面</li></ul><h3 id="业务层-business-layer" tabindex="-1">业务层 (Business Layer) <a class="header-anchor" href="#业务层-business-layer" aria-label="Permalink to &quot;业务层 (Business Layer)&quot;">​</a></h3><ul><li><strong>AgentLoop</strong>: 核心业务逻辑</li><li><strong>工具系统</strong>: AI 能力扩展</li><li><strong>会话管理</strong>: 对话状态维护</li></ul><h3 id="数据层-data-layer" tabindex="-1">数据层 (Data Layer) <a class="header-anchor" href="#数据层-data-layer" aria-label="Permalink to &quot;数据层 (Data Layer)&quot;">​</a></h3><ul><li><strong>SessionManager</strong>: 会话持久化</li><li><strong>MemoryStore</strong>: 长期记忆存储</li><li><strong>SkillsLoader</strong>: 技能文件加载</li></ul><h3 id="基础设施层-infrastructure-layer" tabindex="-1">基础设施层 (Infrastructure Layer) <a class="header-anchor" href="#基础设施层-infrastructure-layer" aria-label="Permalink to &quot;基础设施层 (Infrastructure Layer)&quot;">​</a></h3><ul><li><strong>MessageBus</strong>: 消息路由</li><li><strong>CronService</strong>: 定时任务调度</li><li><strong>HeartbeatService</strong>: 定期任务触发</li></ul><h2 id="设计模式应用" tabindex="-1">设计模式应用 <a class="header-anchor" href="#设计模式应用" aria-label="Permalink to &quot;设计模式应用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>位置</th><th>作用</th></tr></thead><tbody><tr><td>观察者模式</td><td>MessageBus</td><td>事件驱动架构</td></tr><tr><td>策略模式</td><td>ProviderRegistry</td><td>多提供商支持</td></tr><tr><td>工厂模式</td><td>ChannelManager</td><td>通道创建</td></tr><tr><td>命令模式</td><td>ToolRegistry</td><td>工具执行</td></tr><tr><td>建造者模式</td><td>ContextBuilder</td><td>上下文组装</td></tr><tr><td>单例模式</td><td>SessionManager</td><td>会话管理</td></tr></tbody></table><h2 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to &quot;数据流&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户消息 → Channel → MessageBus.inbound</span></span>
<span class="line"><span>    → AgentLoop → LLM + Tools → MessageBus.outbound</span></span>
<span class="line"><span>    → Channel → 用户响应</span></span></code></pre></div><h2 id="扩展点" tabindex="-1">扩展点 <a class="header-anchor" href="#扩展点" aria-label="Permalink to &quot;扩展点&quot;">​</a></h2><p>nanobot 在以下方面提供扩展点：</p><ol><li><strong>新增聊天通道</strong>: 继承 BaseChannel</li><li><strong>新增 LLM 提供商</strong>: 在 ProviderRegistry 注册</li><li><strong>新增工具</strong>: 在 ToolRegistry 注册</li><li><strong>新增技能</strong>: 在 workspace/skills/ 添加 SKILL.md</li><li><strong>新增服务</strong>: 扩展辅助服务层</li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>查看<a href="./overview/directory-structure.html">目录结构</a></li><li>了解<a href="./overview/tech-stack.html">技术栈</a></li><li>阅读<a href="./modules/message-bus.html">消息总线详解</a></li></ul>`,35)])])}const g=n(p,[["render",i]]);export{u as __pageData,g as default};
